/* hovercard.css (#858, surface realized #1911) — the SURFACE of .hovercard-card (background,
 * border, box-shadow, lift) is NOT hand-written: it is the realized `surface` intent this preset
 * declares in composesIntents. It is the build-time emit of
 *   surfaceCss('.hovercard-card', { texture: 'solid', elevation: 3, interaction: 'lift' })
 * from webtraits/surfaceIntentResolver.ts — the ratified realize-a-declared-axis path (#1884), not a
 * raw-CSS surface blob. Layout (position/width/padding/flex), disclosure animation (opacity on
 * [hidden]), and corner radius (`rounded`, the #1912 residual) stay here as the preset's own concern.
 */
.hovercard { position: relative; display: inline-block; }
.hovercard-trigger {
  color: var(--color-primary, #2563eb);
  text-decoration: none;
  font-weight: 500;
}
.hovercard-trigger:hover { text-decoration: underline; }
/* Layout + disclosure (preset-owned). */
.hovercard-card {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  z-index: 60;
  width: 18rem;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.8rem;
  border-radius: 12px;
  opacity: 0;
}
.hovercard-card:not([hidden]) { opacity: 1; }
/* ── BEGIN realized surface (surface{texture:solid, elevation:3, interaction:lift}) — see header. The
   surface transition is unioned with the preset's own `opacity` disclosure transition. ── */
.hovercard-card { background: var(--surface-bg, #fff); border: 1px solid var(--surface-border, var(--color-border, #e2e8f0)); box-shadow: var(--surface-shadow-3, 0 16px 40px -12px rgba(15, 23, 42, 0.25)); transition: opacity 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease; }
.hovercard-card:hover, .hovercard-card:focus-visible { transform: translateY(-2px); box-shadow: var(--surface-shadow-4, 0 24px 56px -16px rgba(15, 23, 42, 0.3)); }
@media (prefers-reduced-motion: reduce) { .hovercard-card { transition: opacity 0.2s ease; } .hovercard-card:hover, .hovercard-card:focus-visible { transform: none; } }
/* ── END realized surface ── */
.hovercard-head { display: flex; gap: 0.6rem; align-items: center; }
.hovercard-avatar { border-radius: 50%; flex-shrink: 0; }
.hovercard-id { display: flex; flex-direction: column; }
.hovercard-handle { color: var(--color-text-muted); font-size: 0.85em; }
.hovercard-bio { font-size: 0.9em; color: var(--color-text-main); }

/* hovercard.js (#858) — progressive enhancement for the hovercard. Baseline
 * markup is a trigger + a hidden card region (the [hidden] attribute keeps it
 * out of the a11y tree until shown). This layers hover-intent open/close delays
 * so a quick pass-through doesn't flash the card, plus focus/blur support and
 * Esc-to-dismiss for keyboard users.
 */
(function () {
  'use strict';
  Array.prototype.forEach.call(document.querySelectorAll('[data-hovercard]'), function (root) {
    var trigger = root.querySelector('[data-hovercard-trigger]');
    var card = root.querySelector('[data-hovercard-card]');
    if (!trigger || !card) return;
    var openDelay = parseInt(root.dataset.openDelay, 10) || 350;
    var closeDelay = 200;
    var openT = null, closeT = null;

    var show = function () {
      clearTimeout(closeT);
      openT = setTimeout(function () { card.hidden = false; }, openDelay);
    };
    var hide = function () {
      clearTimeout(openT);
      closeT = setTimeout(function () { card.hidden = true; }, closeDelay);
    };

    trigger.addEventListener('mouseenter', show);
    trigger.addEventListener('mouseleave', hide);
    card.addEventListener('mouseenter', function () { clearTimeout(closeT); });
    card.addEventListener('mouseleave', hide);

    // Keyboard: focus opens immediately, blur (focus leaving the root) closes.
    trigger.addEventListener('focus', function () { clearTimeout(closeT); card.hidden = false; });
    root.addEventListener('focusout', function (e) {
      if (!root.contains(e.relatedTarget)) card.hidden = true;
    });
    trigger.addEventListener('keydown', function (e) {
      if (e.key === 'Escape' && !card.hidden) { card.hidden = true; }
    });
  });
})();
